script:
frappe.ui.form.on('Kronos Calendar Settings', {
    test_verbindung: function(frm) {
        frappe.call({
            method: 'diakronos.kronos.caldav_client.test_konfiguration',
            args: {
                url: frm.doc.nextcloud_url,
                username: frm.doc.username,
                password: frm.doc.app_password
            },
            callback: function(r) {
                if (r.message) {
                    frappe.msgprint(r.message);
                }
            }
        });
    }
});
